class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable now returns null
        // for empty env vars on Unix. Use an explicit empty-string check
        // to distinguish "not set" from "explicitly empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val is null && !IsEnvironmentVariableDefined("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }

    static bool IsEnvironmentVariableDefined(string variable)
    {
        // IDictionary keys are the definitive set of defined variables,
        // regardless of whether the value is empty or null.
        var all = Environment.GetEnvironmentVariables();
        return all.Contains(variable);
    }
}

